import os
import base64
import xml.etree.ElementTree as ET
from flask import Flask, request, session, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, persistent key in production

# Define SAML namespaces
# It's crucial to use the correct namespaces for parsing
SAML_PROTOCOL_NAMESPACE = "{urn:oasis:names:tc:SAML:2.0:protocol}"
SAML_ASSERTION_NAMESPACE = "{urn:oasis:names:tc:SAML:2.0:assertion}"

